import { readFile, writeFile } from 'node:fs/promises';

const files = ['scripts/data/puzzles.js', 'scripts/game/puzzle.js', 'scripts/game/state.js', 'scripts/ui/render.js', 'scripts/main.js'];
const source = await Promise.all(files.map((file) => readFile(file, 'utf8')));
const bundle = source
  .map((code) => code.replace(/^import .*?;\r?\n/gm, '').replace(/export (const|function) /g, '$1 '))
  .join('\n');
await writeFile('scripts/app.bundle.js', `/* Generated by scripts/build-webstation-bundle.js */\n${bundle}`);
